CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_fin_money_agent_det() RETURNS trigger AS $BODY$
BEGIN

    if coalesce(NEW.seq_no::text, '') = '' or NEW.seq_no = 0 then
        select max(seq_no) into STRICT NEW.seq_no 
        from sc_fin_money_agent_det 
        where AGENT_NO  = NEW.AGENT_NO 
        and item_no = NEW.item_no;
        NEW.seq_no := coalesce(NEW.seq_no,0)  + 1;
    end if;

--    if :old.membership_no is null and :new.membership_no is not null then 
