--        :new.action_br := current_setting('app.login_br', true);
--    end if;
    if coalesce(NEW.status::text, '') = '' then NEW.status :='0';end if;

    if coalesce(NEW.action_user::text, '') = '' then NEW.action_user := current_setting('app.login_id', true);end if;
    if coalesce(NEW.action_date::text, '') = '' then NEW.action_date := statement_timestamp();end if;
    if coalesce(NEW.action_br::text, '') = '' then NEW.action_br := current_setting('app.login_br', true);end if;

RETURN NEW;
end
